import{_ as r,o as a,c as l,aB as t}from"./chunks/framework.BmQUALwd.js";const u=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md","lastUpdated":null}'),i={name:"changelog.md"};function o(n,e,d,p,s,c){return a(),l("div",null,[...e[0]||(e[0]=[t('<h1 id="Changelog" tabindex="-1">Changelog <a class="header-anchor" href="#Changelog" aria-label="Permalink to &quot;Changelog {#Changelog}&quot;">​</a></h1><h2 id="Unreleased" tabindex="-1">Unreleased <a class="header-anchor" href="#Unreleased" aria-label="Permalink to &quot;Unreleased {#Unreleased}&quot;">​</a></h2><h2 id="v0.10.0-2026-04-24" tabindex="-1">v0.10.0 - 2026-04-24 <a class="header-anchor" href="#v0.10.0-2026-04-24" aria-label="Permalink to &quot;v0.10.0 - 2026-04-24 {#v0.10.0-2026-04-24}&quot;">​</a></h2><ul><li><p>Enable <code>sharding_indexed</code> codec for Zarr v3 <a href="https://github.com/JuliaIO/Zarr.jl/pull/241" target="_blank" rel="noreferrer">#241</a></p><ul><li><p>outer chunks (shards) are now split into inner chunks with a byte-range index, enabling efficient partial reads of large arrays</p></li><li><p>Python zarr interoperability tests for sharded arrays using real fixtures generated via PythonCall/zarr-python</p></li><li><p>Function-based codec registration system with typed <code>CodecEntry</code> for extensible V3 codec parsing</p></li><li><p><code>sharding_indexed</code> codec context propagation: inner codec parser now receives element-size context so codecs like <code>blosc</code> get the correct <code>typesize</code></p></li><li><p><code>sharding_indexed</code> decode double-shift bug for <code>index_location=:start</code>: shard index offsets are now treated as absolute byte offsets from the shard start in all cases</p></li><li><p><code>sharding_indexed</code> decode fill value: <code>zdecode!</code> now accepts an optional <code>fill_value</code> argument so missing inner chunks are filled with the array fill value instead of <code>zero(T)</code></p></li><li><p><code>pipeline_decode!</code> for <code>V2Pipeline</code> now accepts the <code>fill_value</code> keyword argument (ignored, but required to match the unified call site in <code>ZArray.readblock!</code>)</p></li><li><p>Ragged inner chunks in <code>ShardingCodec</code> handled correctly</p></li></ul></li><li><p>fixes UI str parsing <a href="https://github.com/JuliaIO/Zarr.jl/pull/259" target="_blank" rel="noreferrer">#259</a></p></li><li><p>added zarr_format to ZGroup <a href="https://github.com/JuliaIO/Zarr.jl/pull/258" target="_blank" rel="noreferrer">#258</a></p></li><li><p>Add support for S3Path and remove deprecated global_aws_config() <a href="https://github.com/JuliaIO/Zarr.jl/pull/253" target="_blank" rel="noreferrer">#253</a></p></li><li><p>(docs) get started <a href="https://github.com/JuliaIO/Zarr.jl/pull/246" target="_blank" rel="noreferrer">#246</a></p></li><li><p>update badges <a href="https://github.com/JuliaIO/Zarr.jl/pull/245" target="_blank" rel="noreferrer">#245</a></p></li><li><p>setup vitepress <a href="https://github.com/JuliaIO/Zarr.jl/pull/243" target="_blank" rel="noreferrer">#243</a></p></li><li><p>Registration system for chunk key encoding <a href="https://github.com/JuliaIO/Zarr.jl/pull/242" target="_blank" rel="noreferrer">#242</a></p></li><li><p>test: Consolidate CondaPkg.add calls <a href="https://github.com/JuliaIO/Zarr.jl/pull/240" target="_blank" rel="noreferrer">#240</a></p></li><li><p>test: Read Julia-generated v3 fixtures with Python zarr <a href="https://github.com/JuliaIO/Zarr.jl/pull/239" target="_blank" rel="noreferrer">#239</a></p></li><li><p>Use CondaPkg.jl#206 for nightly, fix manifest_uuid_path <a href="https://github.com/JuliaIO/Zarr.jl/pull/238" target="_blank" rel="noreferrer">#238</a></p></li><li><p>fix docs build <a href="https://github.com/JuliaIO/Zarr.jl/pull/237" target="_blank" rel="noreferrer">#237</a></p></li><li><p>consolidate methods <a href="https://github.com/JuliaIO/Zarr.jl/pull/235" target="_blank" rel="noreferrer">#235</a></p></li><li><p>Add AbstractChunkKeyEncoding <a href="https://github.com/JuliaIO/Zarr.jl/pull/234" target="_blank" rel="noreferrer">#234</a></p></li><li><p>V3 codec pipeline, group creation, and Python interop <a href="https://github.com/JuliaIO/Zarr.jl/pull/232" target="_blank" rel="noreferrer">#232</a></p></li><li><p>Add read support for big endian <a href="https://github.com/JuliaIO/Zarr.jl/pull/230" target="_blank" rel="noreferrer">#230</a></p></li><li><p>Indent method/type signatures on docstrings <a href="https://github.com/JuliaIO/Zarr.jl/pull/229" target="_blank" rel="noreferrer">#229</a></p></li><li><p>Promote header levels in tutorial.md <a href="https://github.com/JuliaIO/Zarr.jl/pull/228" target="_blank" rel="noreferrer">#228</a></p></li><li><p>Continue on v3 PR <a href="https://github.com/JuliaIO/Zarr.jl/pull/226" target="_blank" rel="noreferrer">#226</a></p></li><li><p>move AWSS3 into extension <a href="https://github.com/JuliaIO/Zarr.jl/pull/224" target="_blank" rel="noreferrer">#224</a></p></li></ul>',4)])])}const g=r(i,[["render",o]]);export{u as __pageData,g as default};
